module hazard_detection_counter (
    input wire clk,
    input wire reset,
    output reg [1:0] count
);
    reg [1:0] obf_next_count;

    always @(*) begin
        if (reset) begin
            obf_next_count = 2'b00;
        end else begin
            case (count)
                2'b00: obf_next_count = 2'b01;
                2'b01: obf_next_count = 2'b10;
                2'b10: obf_next_count = 2'b11;
                2'b11: obf_next_count = 2'b00;
                default: obf_next_count = 2'b00;
            endcase
        end
    end

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            count <= 2'b00;
        end else begin
            count <= obf_next_count;
        end
    end
endmodule
